var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우...... 대체 몇 번이나 설명해야 하지?","JPN":"ふう……いったい何回説明すればわかってくれるかしら？","ENG":"*Sigh* How many times do I have to explain it to you?","TWN":"呼……我還要說多少次？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말하지만 전기란 건 사용하면 돈을 내야 해.","JPN":"もう一度言うけど、電気というのは使ったらお金がかかるの。","ENG":"Electricity costs money.","TWN":"我再說一遍，用電必須交電費。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 우리 회사는 돈이 별로 없어.","JPN":"だけど、うちの会社はお金の余裕がないの。","ENG":"And our company doesn't have much money.","TWN":"但我們公司沒有多少資金。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 멋대로 전기를 끌어다 쓰지 말라고 했잖니?","JPN":"だから勝手に電気を横取りして使わないでって\\n言ったわよね？","ENG":"I told you not to waste electricity, didn't I?","TWN":"所以你不能這樣隨意用電，我說多少次了？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오늘로만 벌써 세 번째 정전이야. 경고는 줄 만큼 줬다고 생각하는데?","JPN":"今日だけでもう3回目の停電よ？　十分注意した\\nはずなのに。","ENG":"That was the third blackout today. How many more warnings do you need?","TWN":"這已經是第三次停電了，我到底還要警告多少次？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"하지만 고장 난 로봇을 고쳐주려면 그 정도 전력은 필요해.","JPN":"でも、壊れたロボットを修理するにはそれくらいの\\n電力が必要なの。","ENG":"But I need electricity to repair broken robots.","TWN":"但要修復損壞的機器人必須用到電力啊。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"게다가 여긴 도움이 필요한 로봇들이 엄청나게 많은걸!","JPN":"それに、ここは助けが必要なロボットだらけだから\\n仕方ないもん！","ENG":"And this place is filled with broken robots.","TWN":"而且這裡有很多需要幫助的機器人！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"망가진 로봇도 가족이니까 당연히 고쳐줘야 하잖아?","JPN":"壊れたロボットも家族なんだから、当然治して\\nあげるべきよね？","ENG":"They're also our family. We have to fix them.","TWN":"損壞的機器人也是家人，所以必須幫它們修理！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"넌 잘 모르겠지만 회사라는 곳은 수지타산이라는 제 1원칙을 지켜야 굴러가는 곳이야.","JPN":"あなたはまだわからないだろうけど、会社というものは\\n費用対効果を第一に考えないと維持できないの。","ENG":"You may not understand this, but companies exist to make profits.","TWN":"你可能還不瞭解，公司的第一原則是收支平衡。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"싸구려 청소로봇을 수리하기 위해 한 달치 전기요금을 지불하는 회사는 어디에도 없어.","JPN":"安価な掃除ロボットを修理するために、一か月分の\\n電気料金をかける会社なんてどこにもないわよ。","ENG":"No company can survive by paying a month's worth of electricity on a cheap cleaning robot.","TWN":"沒有任何公司會為了 一個廉價的清潔機器人支付一整個月的電費。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네가 얼마나 대단한진 모르겠지만, 계속 이런 식으로 굴면 전원을 꺼버릴 거야.","JPN":"あなたがどれだけすごいかはわからないけど、このままなら\\n電源を切ってしまいますからね？","ENG":"I don't care how important you are to the Boss. Keep misbehaving like this, and I'm going to turn off your power.","TWN":"我不知道你有多大能耐，但你如果繼續這樣，我只能關掉你的電源。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠니?","JPN":"わかってくれるかしら？","ENG":"Is that understood?","TWN":"知道了嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으으으......","JPN":"むうう……","ENG":"Ugh...","TWN":"唔……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"치사해! 치사해!","JPN":"ケチ！　ケチ！　副社長のケチ！","ENG":"It's not fair! It's just not fair!","TWN":"好卑鄙！好卑鄙！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"치사한 사람이야! 아빠가 부사장님 혼내줘!","JPN":"ケチ臭いったらありゃしない！　パパからも\\n副社長に何か言ってよ！","ENG":"She's a cheapskate! Daddy, punish her!","TWN":"太卑鄙了！爸爸快罵罵副總！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......회사를 위해 결단을 내리셔야 합니다, 사장님.","JPN":"……会社のために決断が必要です、社長。","ENG":"Boss, you have to make the decision for your company.","TWN":"……老闆，你必須為公司做出決定。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당장 저 골칫거리 깡통의 전원을 끄고 어디 창고에라도 처박아두시죠.","JPN":"今すぐあの厄介なボロ缶の電源を切って、どこかの\\n倉庫にでもぶちこんではいかがでしょう。","ENG":"Turn off that troublesome tin can right now and put it in a corner of a warehouse somewhere.","TWN":"快把這煩人的破銅爛鐵的電源關掉，扔進倉庫裡。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};